        for i in 0..rgb_new.len() {
            let diff = (rgb_new[i] - rgb_old[i]).abs();
            assert!(diff < 0.05, "pixel {i}: old={:.4} new={:.4} diff={:.4}", rgb_old[i], rgb_new[i], diff);
